import torch

# Example tensor input
x = torch.randn(10, 3, 32, 32)  # Example shape

# Example forward operator with a 'forward' method
def example_forward(tensor):
    return tensor * 2  # Simple operation for demonstration

class ExampleForwardOp:
    def forward(self, x):
        return example_forward(x)

forward_op = ExampleForwardOp()

# Apply the forward operator
result = forward_operator(x, forward_op)
print(result.shape)  # Output shape will be the same as input shape
